class Solution {
    public int countBinarySubstrings(String s) {
        int[] counts = new int[2];
        int prevCount = 0;
        int result = 0;
        for (char c : s.toCharArray()) {
            counts[c - '0']++;
            result += Math.min(counts[0], counts[1]);
            if (counts[0] == prevCount) {
                counts[0] = 0;
                prevCount = counts[1];
            } else {
                counts[1] = 0;
                prevCount = counts[0];
            }
        }
        return result;
    }
}
```
